    ('6b766ce1-f4dc-4230-bf4b-f89f2aab55b7', 'Dra TATIANE', 'ATIVO', 'https://jcvmilqtmjyjynczwmlu.supabase.co/storage/v1/object/public/ad-creatives/1773254610641-01jz2ss860a.jpeg', '["https://jcvmilqtmjyjynczwmlu.supabase.co/storage/v1/object/public/ad-creatives/1773254610641-01jz2ss860a.jpeg", "https://jcvmilqtmjyjynczwmlu.supabase.co/storage/v1/object/public/ad-creatives/1773254612306-v1j5eoj6m4m.jpeg", "https://jcvmilqtmjyjynczwmlu.supabase.co/storage/v1/object/public/ad-creatives/1773254613086-7wun9clbdt6.jpeg"]'::jsonb, 'Matheus', 'Brayton', '2026-03-13 20:54:48.298+00', '2026-03-11 18:43:34.0277+00', '2026-03-11 18:43:34.0277+00')
  ) AS v(
    id, client_name, status, image_url, image_urls, created_by_name, completed_by_name, completed_at, created_at, updated_at
  )
), resolved AS (
  SELECT
    r.id,
    NULL::uuid AS client_id,
    r.client_name,
    r.status,
    r.image_url,
    r.image_urls,
    COALESCE(
      (SELECT p.id FROM public.profiles p WHERE lower(p.full_name) = lower(r.created_by_name) LIMIT 1),
      (SELECT p.id FROM public.profiles p WHERE lower(p.full_name) LIKE '%' || lower(r.created_by_name) || '%' LIMIT 1),
      (SELECT p.id FROM public.profiles p WHERE lower(p.full_name) LIKE '%amanda%' LIMIT 1),
      (SELECT p.id FROM public.profiles p WHERE lower(p.full_name) LIKE '%matheus%' LIMIT 1)
    ) AS created_by_user_id,
    r.created_by_name,
    (SELECT p.id FROM public.profiles p WHERE lower(p.full_name) = lower(r.completed_by_name) LIMIT 1) AS completed_by_user_id,
    r.completed_by_name,
    r.completed_at::timestamptz,
    r.created_at::timestamptz,
    r.updated_at::timestamptz
  FROM input_rows r
)
INSERT INTO public.ad_creatives (
  id, client_id, client_name, image_url, image_urls, status,
  created_by_user_id, created_by_name, completed_by_user_id, completed_by_name,
  completed_at, created_at, updated_at
)
SELECT
  id, client_id, client_name, image_url, image_urls, status,
  created_by_user_id, created_by_name, completed_by_user_id, completed_by_name,
  completed_at, created_at, updated_at
FROM resolved
ON CONFLICT (id) DO UPDATE SET
  client_id = EXCLUDED.client_id,
  client_name = EXCLUDED.client_name,
  image_url = EXCLUDED.image_url,
  image_urls = EXCLUDED.image_urls,
  status = EXCLUDED.status,
  created_by_user_id = EXCLUDED.created_by_user_id,
  created_by_name = EXCLUDED.created_by_name,
  completed_by_user_id = EXCLUDED.completed_by_user_id,
  completed_by_name = EXCLUDED.completed_by_name,
  completed_at = EXCLUDED.completed_at,
  created_at = EXCLUDED.created_at,
  updated_at = EXCLUDED.updated_at;

COMMIT;

